commits.content:
.report-page{
padding:40px;
background:#f8fafc;
}

.report-container{
background:white;
padding:40px;
border-radius:8px;
}

.report-table{
width:100%;
border-collapse:collapse;
margin-top:20px;
}

.report-table th,
.report-table td{
border:1px solid #ddd;
padding:8px;
}

.diff-file{
margin-top:40px;
}

.diff-columns{
display:flex;
gap:20px;
}

.diff-column{
flex:1;
background:#f9fafb;
padding:10px;
}

.diff-header{
font-weight:bold;
padding:6px;
margin-bottom:6px;
}

.diff-header.red{
color:#ef4444;
}

.diff-header.green{
color:#16a34a;
}

.diff-line{
font-family:monospace;
padding:3px;
}

.diff-line.added{
background:#e6ffed;
}

.diff-line.removed{
background:#ffeef0;
}

.diff-line.modified{
background:#fff5b1;
}

.download-btn{
margin-bottom:20px;
padding:10px 20px;
background:#4f46e5;
color:white;
border:none;
border-radius:6px;
cursor:pointer;
}
